        console.log(`   ✓ Archived: ${domain}/${filePath.split(/[\\/]/).pop()} → ${dest.split(/[\\/]/).slice(-3).join('/')}`);
      }
      domainArchived++;
      totalArchived++;
    }

    if (notes.length > 0) {
